class Solution:
    def cherryPickup(self, grid):
        n = len(grid)
        NEG = float('-inf')
        dp = [[NEG] * n for _ in range(n)]
        dp[0][0] = grid[0][0]
        for s in range(1, 2 * n - 2 + 1):
            ndp = [[NEG] * n for _ in range(n)]
            for x1 in range(max(0, s - (n - 1)), min(n - 1, s) + 1):
                y1 = s - x1
                if grid[x1][y1] == -1:
                    continue
                for x2 in range(max(0, s - (n - 1)), min(n - 1, s) + 1):
                    y2 = s - x2
                    if grid[x2][y2] == -1:
                        continue
                    best = NEG
                    for px1 in (x1, x1 - 1):
                        for px2 in (x2, x2 - 1):
                            if 0 <= px1 < n and 0 <= px2 < n and dp[px1][px2] != NEG:
                                if dp[px1][px2] > best:
                                    best = dp[px1][px2]
                    if best == NEG:
                        continue
                    gain = grid[x1][y1]
                    if x1 != x2:
                        gain += grid[x2][y2]
                    ndp[x1][x2] = best + gain
            dp = ndp
        ans = dp[n - 1][n - 1]
        return 0 if ans == NEG else ans

