import sys
from functools import lru_cache
class Solution:
    def cherryPickup(self, grid):
        n = len(grid)
        sys.setrecursionlimit(1000000)
        NEG = float('-inf')
        @lru_cache(maxsize=None)
        def dp(r1, c1, r2):
            c2 = r1 + c1 - r2
            if r1 >= n or c1 >= n or r2 >= n or c2 >= n or c2 < 0 or grid[r1][c1] == -1 or grid[r2][c2] == -1:
                return NEG
            if r1 == n - 1 and c1 == n - 1:
                return grid[r1][c1]
            gain = grid[r1][c1]
            if (r1, c1) != (r2, c2):
                gain += grid[r2][c2]
            best = max(dp(r1 + 1, c1, r2 + 1), dp(r1 + 1, c1, r2), dp(r1, c1 + 1, r2 + 1), dp(r1, c1 + 1, r2))
            if best == NEG:
                return NEG
            return gain + best
        result = dp(0, 0, 0)
        dp.cache_clear()
        return max(0, result if result != NEG else 0)

