var cherryPickup = function(grid) {
    const n = grid.length;
    const NEG = -Infinity;
    const memo = new Map();
    function dp(r1, c1, r2) {
        const c2 = r1 + c1 - r2;
        if (r1 >= n || c1 >= n || r2 >= n || c2 >= n || c2 < 0 || grid[r1][c1] === -1 || grid[r2][c2] === -1) return NEG;
        if (r1 === n - 1 && c1 === n - 1) return grid[r1][c1];
        const key = r1 * n * n + c1 * n + r2;
        if (memo.has(key)) return memo.get(key);
        let gain = grid[r1][c1];
        if (!(r1 === r2 && c1 === c2)) gain += grid[r2][c2];
        const best = Math.max(dp(r1 + 1, c1, r2 + 1), dp(r1 + 1, c1, r2), dp(r1, c1 + 1, r2 + 1), dp(r1, c1 + 1, r2));
        const res = best === NEG ? NEG : gain + best;
        memo.set(key, res);
        return res;
    }
    const result = dp(0, 0, 0);
    return Math.max(0, result === NEG ? 0 : result);
};
